// frontend/src/services/api.js
import axios from 'axios';

const API  = 'http://localhost:5000/api';
const PRED = 'http://localhost:8001';

// ─── Places ──────────────────────────────────────────────
export const getPlaces = (category = 'all', search = '') =>
  axios.get(`${API}/places`, { params: { category, search } }).then(r => r.data);

export const getPlaceById = (id) =>
  axios.get(`${API}/places/${id}`).then(r => r.data);

export const getNearbyPlaces = (lat, lng, category = 'all') =>
  axios.get(`${API}/places/search/nearby`, { params: { lat, lng, category } }).then(r => r.data);

export const addPlace = (data) =>
  axios.post(`${API}/places`, data).then(r => r.data);

// ─── Prediction ───────────────────────────────────────────
// NOW passes category so prediction is accurate per place type
export const getPrediction = (place_id, category = 'mall', target_hour = null, target_day = null) =>
  axios.post(`${PRED}/predict`, {
    place_id:    String(place_id),
    category:    category,
    target_hour: target_hour,
    target_day:  target_day,
  })
  .then(r => r.data)
  .catch(() => ({
    crowd_level:    'Unknown',
    crowd_score:    0,
    active_users:   0,
    waiting_time:   'N/A',
    estimated_cost: 'N/A',
    best_time:      'N/A',
    trend:          'N/A',
    confidence:     'low',
  }));

export const getHourlyPattern = (category, day) =>
  axios.get(`${PRED}/hourly/${category}/${day}`).then(r => r.data).catch(() => null);

export const getBestDay = (category) =>
  axios.get(`${PRED}/best-day/${category}`).then(r => r.data).catch(() => null);
